queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?tour_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBoat_Tours ?child ; p:hasMaritime_Villages ?parent . } GROUP BY ?child }
  ?child p:tour_name ?tour_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Maritime_Villages } }
  FILTER(?nf = ?total)
}

